TEST(CropStreambufTest, Crop6x7) {
    const uint8_t expected6x7[] = {
        0x00, 0x01, 0x02, 0x03, 0x04, 0x05,
        0x10, 0x11, 0x12, 0x13, 0x14, 0x15,
        0x20, 0x21, 0x22, 0x23, 0x24, 0x25,
        0x30, 0x31, 0x32, 0x33, 0x34, 0x35,
        0x40, 0x41, 0x42, 0x43, 0x44, 0x45,
        0x50, 0x51, 0x52, 0x53, 0x54, 0x55,
        0x60, 0x61, 0x62, 0x63, 0x64, 0x65,
    };

    MemoryStream src(raster10x10);
    src.put(0x0c);
    src.put(0x0f);
    Utility::CropStreambuf cs(*src.rdbuf(), 10, 10, 6, 7);

    MemoryStream dest;
    for (std::size_t i = 0; i < 7; i++) {
        char line[6];
        ASSERT_EQ(cs.sgetn(line, sizeof(line)), sizeof(line));
        dest.write(line, sizeof(line));
    }

    EXPECT_THAT(dest.Buffer(), testing::ElementsAreArray(expected6x7));
    EXPECT_THAT(src.Buffer(), testing::ElementsAre(0x0c, 0x0f));
}

TEST(CropStreambufTest, Crop6x7_EOF) {
    const uint8_t expected6x5[] = {
        0x00, 0x01, 0x02, 0x03, 0x04, 0x05,
        0x10, 0x11, 0x12, 0x13, 0x14, 0x15,
        0x20, 0x21, 0x22, 0x23, 0x24, 0x25,
        0x30, 0x31, 0x32, 0x33, 0x34, 0x35,
        0x40, 0x41, 0x42, 0x43, 0x44, 0x45,
    };

    MemoryStream src(raster10x5);
    Utility::CropStreambuf cs(*src.rdbuf(), 10, 10, 6, 7);

    MemoryStream dest;
    for (std::size_t i = 0; i < 7; i++) {
        char line[6];
        std::streamsize read = cs.sgetn(line, sizeof(line));
        dest.write(line, read);
    }
    EXPECT_EQ(cs.sgetc(), std::streambuf::traits_type::eof());
    EXPECT_EQ(cs.sbumpc(), std::streambuf::traits_type::eof());

    EXPECT_THAT(dest.Buffer(), testing::ElementsAreArray(expected6x5));
}

TEST(CropStreambufTest, Crop6x7_PartialLineRead) {
    const uint8_t expected6x7[] = {
        0x00, 0x01, 0x02, 0x03, 0x04, 0x05,
        0x10, 0x11, 0x12, 0x13, 0x14, 0x15,
        0x20, 0x21, 0x22, 0x23, 0x24, 0x25,
        0x30, 0x31, 0x32, 0x33, 0x34, 0x35,
        0x40, 0x41, 0x42, 0x43, 0x44, 0x45,
        0x50, 0x51, 0x52, 0x53, 0x54, 0x55,
        0x60, 0x61, 0x62, 0x63, 0x64, 0x65,
    };

    MemoryStream src(raster10x10);
    src.put(0x0c);
    src.put(0x0f);
    Utility::CropStreambuf cs(*src.rdbuf(), 10, 10, 6, 7);

    MemoryStream dest;
    for (std::size_t i = 0; i < 7; i++) {
        char line[6];
        ASSERT_EQ(cs.sgetn(line, 2), 2);
        ASSERT_EQ(cs.sgetn(line + 2, 4), 4);
        dest.write(line, sizeof(line));
    }

    EXPECT_THAT(dest.Buffer(), testing::ElementsAreArray(expected6x7));
    EXPECT_THAT(src.Buffer(), testing::ElementsAre(0x0c, 0x0f));
}

